  create policy "Bookings delete for admin"
  on "public"."bookings"
  as permissive
  for delete
  to authenticated
using (public.is_admin());



  create policy "Bookings select for owner or admin"
  on "public"."bookings"
  as permissive
  for select
  to authenticated
using ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))));



  create policy "Bookings update for owner or admin"
  on "public"."bookings"
  as permissive
  for update
  to authenticated
using ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))))
with check ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))));



  create policy "Rep availability delete for owner or admin"
  on "public"."rep_availability"
  as permissive
  for delete
  to authenticated
using ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))));



  create policy "Rep availability insert for owner or admin"
  on "public"."rep_availability"
  as permissive
  for insert
  to authenticated
with check (((sales_id IS NULL) OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid()))) OR public.is_admin()));



  create policy "Rep availability select for owner or admin"
  on "public"."rep_availability"
  as permissive
  for select
  to authenticated
using ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))));



  create policy "Rep availability update for owner or admin"
  on "public"."rep_availability"
  as permissive
  for update
  to authenticated
using ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))))
with check ((public.is_admin() OR (sales_id = ( SELECT sales.id
   FROM public.sales
  WHERE (sales.user_id = auth.uid())))));


CREATE TRIGGER notify_on_booking_created_trigger AFTER INSERT ON public.bookings FOR EACH ROW EXECUTE FUNCTION public.notify_on_booking_created();


